// Quick lookup
export const BRAND_MAP = Object.fromEntries(ALL_BRANDS.map((b) => [b.id, b]));

// Project lookup: projectId → { brand, project }
export const PROJECT_MAP: Record<string, { brand: Brand; project: Project }> = {};
ALL_BRANDS.forEach((brand) => {
  (brand.projects ?? []).forEach((project) => {
    PROJECT_MAP[project.id] = { brand, project };
  });
});

